import{_ as p,o as t,c as i,a6 as o,fw as l,jD as n,jE as e,jF as g,fY as m,iJ as s,jG as _,jH as c,jI as h,jJ as d,jK as b,jL as f,jM as j,jN as x,jO as P,jP as k,iG as a,jQ as u,fx as D,jR as v,gU as w,jS as A,jT as T,jU as S,jv as y,jw as F,jx as $,jy as B,jz as C,jA as E,iE as H,iF as N,iH as I,jB as J,jC as K}from"./chunks/framework.UYVGz2W_.js";const M=JSON.parse('{"title":"レビュー","description":"","frontmatter":{},"headers":[],"relativePath":"ja/review/index.md","filePath":"ja/review/index.md"}'),R={name:"ja/review/index.md"};function V(W,r,G,L,O,U){return t(),i("div",null,[...r[0]||(r[0]=[o('<h1 id="レビュー" tabindex="-1">レビュー <a class="header-anchor" href="#レビュー" aria-label="Permalink to “レビュー”">​</a></h1><h2 id="レビュータスク" tabindex="-1">レビュータスク <a class="header-anchor" href="#レビュータスク" aria-label="Permalink to “レビュータスク”">​</a></h2><p>アーティストが自分の作品を誰かに<strong>レビュー</strong>してもらいたい場合、タスクのステータスを <img src="'+l+'" alt="wfa"> に変更します。</p><p>ステータスをクリックすると右側のパネルが開き、レビューを開始できます。</p><p>右パネルからバージョンを閲覧し、パネルの端をつかんで拡大したり、このアイコンをクリックしてフルスクリーン表示にすることもできます <img src="'+n+'" alt="フルスクリーン">。</p><p><img src="'+e+'" alt="グローバルページでのレビュー"></p><p>同様に、3Dファイル（<code>.glb</code>ファイル）をワイヤーフレームとして確認したり、<code>.HDR</code>ファイルを追加して照明を確認することもできます。</p><p>カーソルをドラッグ＆ドロップして3Dファイルを移動したり、スクロールホイールでズームイン・ズームアウトしたりできます。</p><p><img src="'+g+'" alt="3Dワイヤーフレームの確認"></p><p><img src="'+m+'" alt="プレビュー背景の例"></p><p>詳細は<strong>カスタマイズ</strong>のセクションを参照してください。 <a href="./../configure-kitsu/#_3d-backgrounds">パイプラインのカスタマイズ</a></p><p>使用する色を選択し、<strong>鉛筆</strong>ツールでプレビュー上に直接描画することができます <img src="'+s+'" alt="鉛筆">。</p><p><img src="'+_+'" alt="レビュー描画"></p><h3 id="描画注釈" tabindex="-1">描画注釈 <a class="header-anchor" href="#描画注釈" aria-label="Permalink to “描画注釈”">​</a></h3><p>フレームに<strong>テキスト</strong>で注釈を付けることもできます。</p><p><img src="'+c+'" alt="レビュー描画テキスト"></p><p><strong>注釈</strong>を一時的に非表示にしたい場合は、<strong>「万年筆」</strong>ボタンをクリックします。 <img src="'+h+'" alt="注釈を隠す"></p><h3 id="フレームへのタグ付け" tabindex="-1">フレームへのタグ付け <a class="header-anchor" href="#フレームへのタグ付け" aria-label="Permalink to “フレームへのタグ付け”">​</a></h3><p>コメント内で特定のフレームを参照したい場合は、<code>@</code>を入力するとサブメニューが開き、チームリストが表示されます。その後、<strong>「フレーム」</strong>の入力を開始します。</p><p>これにより、現在のフレームのタイムスタンプがコメントに追加され、タイムスタンプをクリックすると、そのフレームにジャンプします。</p><p><img src="'+d+'" alt="フレームにタグを付ける"></p><h3 id="注釈のエクスポート" tabindex="-1">注釈のエクスポート <a class="header-anchor" href="#注釈のエクスポート" aria-label="Permalink to “注釈のエクスポート”">​</a></h3><p><strong>スクリーンショットを添付ファイルとして添付</strong>することで、各フレームの描画をエクスポートすることもできます。</p><p>添付ファイルを追加**]ボタンをクリックします。</p><p><img src="'+b+'" alt="添付ファイル"></p><p>添付オプションで、<strong>注釈のスナップショットを添付する</strong>こともできます。これにより、注釈を付けたフレームをコメントの添付ファイルとして追加することができます。これは、フィードバックの中で特定の注釈を強調したい場合に便利です。</p><p><img src="'+f+'" alt="添付のスナップショット"></p><p>ボタンをクリックすると、Kitsuが注釈付きのすべてのフレームを取得し、結果を表示します。 <strong>確認</strong>をクリックすると、それらを公開できます。</p><p><img src="'+j+'" alt="添付のスナップショット詳細"></p><h3 id="注釈の削除" tabindex="-1">注釈の削除 <a class="header-anchor" href="#注釈の削除" aria-label="Permalink to “注釈の削除”">​</a></h3><p>線を削除したい場合は、鉛筆アイコンを再度クリックします。カーソルが多方向クロス <img src="'+x+'" alt="鉛筆"> に変わり、線を削除したい場所まで移動して選択します。</p><p><img src="'+P+'" alt="レビュー描画"></p><p>方向を示す十字のアイコンで線を選択し、削除アイコン <img src="'+k+'" alt="Delete line"> を押します。</p><h3 id="画像の比較" tabindex="-1">画像の比較 <a class="header-anchor" href="#画像の比較" aria-label="Permalink to “画像の比較”">​</a></h3><p><strong>フルスクリーン</strong>モードにすると、<strong>比較</strong>ボタン <img src="'+a+'" alt="compare button"> をクリックして、2つのタスクタイプまたはバージョンを並べて比較することができます。</p><p><img src="'+u+'" alt="比較ボタン"></p><p>ここから、アーティストに変更を依頼する場合は、ステータスを <img src="'+D+'" alt="再提出"> に変更できます。</p><p>あるいは、アーティストに作業を承認したことを通知するために、 <img src="'+v+'" alt="完了"> に変更することもできます。</p><h2 id="コンセプトのレビュー" tabindex="-1">コンセプトのレビュー <a class="header-anchor" href="#コンセプトのレビュー" aria-label="Permalink to “コンセプトのレビュー”">​</a></h2><p>アーティストがコンセプトをアップロードすると、スーパーバイザーまたはディレクターがそれをレビューすることができます。</p><p>コンセプトをレビューするには、画面上部のナビゲーションメニューを使用してコンセプトページを選択します。</p><p><img src="'+w+'" alt="メニューコンセプト"></p><p>アップロードされたすべてのコンセプト、そのステータス、割り当て、リンクされたアセットを確認できます。</p><p><img src="'+A+'" alt="コンセプト入力済みステータス"></p><p>コンセプトを確認するには、ステータスをクリックしてコメントパネルを開きます。コメントパネルを拡大したり、フルスクリーン表示にしたりすることができます。</p><p>次に、コメントを入力し、ステータスとして<strong>承認済み</strong>または<strong>却下済み</strong>を選択し、<strong>投稿</strong>ボタンで確定します。</p><p><img src="'+T+'" alt="コンセプトステータスコメント"></p><p><strong>ステータス</strong>フィルターを使用してページをフィルタリングし、<strong>ニュートラル</strong>ステータスのすべてのコンセプトを表示することができます。また、アーティスト別にフィルタリングしたり、ソート順を変更することもできます。</p><p><img src="'+S+'" alt="コンセプトステータスフィルター"></p><h2 id="プレイリスト" tabindex="-1">プレイリスト <a class="header-anchor" href="#プレイリスト" aria-label="Permalink to “プレイリスト”">​</a></h2><h3 id="プレイリストの作成" tabindex="-1">プレイリストの作成 <a class="header-anchor" href="#プレイリストの作成" aria-label="Permalink to “プレイリストの作成”">​</a></h3><p>プレイリストは、レビューと承認のために編集されたバージョン/プレビューの一覧です。ドロップダウンメニューに<strong>プレイリスト</strong>ページがあります。</p><p><img src="'+y+'" alt="プレイリストメインメニュー"></p><p><strong>プレイリスト</strong>ページは2つの部分に分かれています。</p><p>(1) あなたのプレイリストの一覧です。ここで新しいプレイリストを<strong>作成</strong>したり、既存のプレイリストを読み込むことができます。</p><ul><li>(2) 最後に作成されたプレイリストと最後に変更されたプレイリスト。</li></ul><p><img src="'+F+'" alt="Playlist page"></p><p><img src="'+$+'" alt="Playlist add button"> ボタンを使用して、<strong>プレイリスト</strong>を作成します。プレイリスト名はデフォルトでは現在の日付と時刻になりますが、変更することができます。 プレイリストを<strong>スタジオ</strong>または<strong>クライアント</strong>と共有するかどうか、また、<strong>ショット</strong>または<strong>アセット</strong>のプレイリストにするかを選択できます。 プレイリストに<strong>タスクタイプ</strong>のタグを追加することもできます。</p><p><img src="'+B+'" alt="プレイリスト追加ページ"></p><h3 id="プレイリストへの追加" tabindex="-1">プレイリストへの追加 <a class="header-anchor" href="#プレイリストへの追加" aria-label="Permalink to “プレイリストへの追加”">​</a></h3><p>プレイリストが作成されたら、検索/フィルタバーを使用して、プレイリストに追加するショットを選択します。</p><p>プロジェクトの大部分を一度に追加したい場合は、<strong>エピソード全体</strong>/<strong>シーケンス全体</strong>を追加するオプションも表示されます。</p><p><strong>Daily pending</strong>（日次保留中）を選択すると、その日の<strong>WFA</strong>タスクがすべて追加されます。</p><p>グローバルショット/アセットページと同じ<strong>フィルタ</strong>を使用できます。例えば、検索バーに<strong>animation=wfa</strong>と入力すると、<strong>アニメーション</strong>段階にあるすべての<strong>WFA</strong>（「ワーク・フォー・アニメーション」の略）タスクを選択できます。<strong>Add selection</strong>（選択を追加）ボタンで選択を検証します。Kitsuは、<strong>アニメーション</strong>段階にある<strong>WFA</strong>ステータスのショットを選択し、<strong>最新のアップロードバージョン</strong>を自動的に読み込みます。</p><p>ショットは画面の上部に表示されます。 変更はすべて自動的に保存されます。</p><p><img src="'+C+'" alt="プレイリストページ"></p><h2 id="レビューコントロール" tabindex="-1">レビューコントロール <a class="header-anchor" href="#レビューコントロール" aria-label="Permalink to “レビューコントロール”">​</a></h2><p>プレイリストを作成すると、いくつかのオプションが利用可能になります。</p><p><img src="'+E+'" alt="プレイリストグローバル"></p><ul><li><p>再生または一時停止</p></li><li><p>プレイリスト内の要素間を移動</p></li><li><p>選択した要素の全体数に対する位置を確認</p></li><li><p>オーディオのミュートまたはミュート解除</p></li><li><p>再生速度の変更：2倍速（x2）、通常速（x1）、半分の速さ（x0.50）、4分の1の速さ（x0.25</p></li><li><p>1つの要素を連続ループ</p></li><li><p>オーディオ波形の表示</p></li><li><p>再生中の注釈の表示</p></li><li><p>プレイリスト全体のタイムコードと比較した、各エレメントのタイムコード（TC）を表示</p></li><li><p>フレーム数を表示</p></li><li><p>プレビュー上でフレーム単位のナビゲーション（キーボードの左矢印キーと右矢印キーも使用可能</p></li><li><p>比較ツールへのアクセス</p></li><li><p>アノテーションの取り消しとやり直しオプション</p></li><li><p>テキストと描画オプション（選択した項目の削除を含む</p></li><li><p>プレイリスト内の全要素のタスクタイプを変更</p></li><li><p>コメントセクションを表示</p></li><li><p>プレイリスト内の要素を非表示</p></li><li><p>LD（低解像度）とHD（高解像度）を切り替え</p></li><li><p>個々の要素を含む<strong>Zip</strong>ファイル、<strong>.csv</strong>テキストファイル、または<strong>Build .mp4</strong>としてプレイリストをダウンロードし、ムービー全体を作成（ショットのみ）</p></li><li><p>フルスクリーンモード</p></li></ul><p>プレイリスト内の各ショット/アセットについて、確認したい<strong>タスク</strong>と<strong>バージョン</strong>を選択できます。</p><p><img src="'+H+'" alt="プレイリストのタスク選択"><img src="'+N+'" alt="プレイリストのバージョン選択"></p><p>また、ショットの2つのタスクを並べて再生することもできます。</p><p>[比較] ボタンをクリックします <img src="'+a+'" alt="比較ボタン"> し、2番目のタスクタイプを選択します。</p><p><img src="'+I+'" alt="プレイリストを並べて表示"></p><p>プレビューから直接ショットにコメントを追加できます。</p><p>[コメント] ボタンをクリックします。</p><p><img src="'+J+'" alt="プレイリストのコメント"></p><p>右パネルにアクセスできるようになりました。このパネルには、コメントの履歴とステータスが表示されます。</p><p>ビデオ上に描画したコメント（タイムラインの下の赤い点）を見ることができます。</p><p><img src="'+K+'" alt="プレイリストコメント"></p><p>[描画]ボタン <img src="'+s+'" alt="描画ボタン">を使用して、動画上に描画したり文字を入力したりすることができます（レビューの実行と同様）。</p><h2 id="レビュールーム" tabindex="-1">レビュールーム <a class="header-anchor" href="#レビュールーム" aria-label="Permalink to “レビュールーム”">​</a></h2><p>レビュールームは、効率的で同期されたデイリーズレビューセッションを行うために設計された共同作業スペースです。これにより、すべての参加者が同時に同じコンテンツを閲覧することができ、リアルタイムのフィードバックやディスカッションが容易になります。</p><p>レビュールームについてさらに詳しく知りたい場合は、<a href="./../playlist-client/#review-room">このセクションを参照してください</a>。</p>',85)])])}const Q=p(R,[["render",V]]);export{M as __pageData,Q as default};
